void ui_event_ScreenBoot(lv_event_t * e)
{
    lv_event_code_t event_code = lv_event_get_code(e);
    lv_obj_t * target = lv_event_get_target(e);
    if(event_code == LV_EVENT_SCREEN_LOAD_START) {
        ProductMove6_Animation(ui_ImageProduct6, 2500);
        ProductMove5_Animation(ui_ImageProduct5, 2200);
        ProductMove4_Animation(ui_ImageProduct4, 1950);
        ProductMove3_Animation(ui_ImageProduct3, 1550);
        ProductMove2_Animation(ui_ImageProduct2, 1250);
        ProductMove1_Animation(ui_ImageProduct1, 1000);
        LogoMove1_Animation(ui_ImageBootLogo1, 0);
        LogoMove2_Animation(ui_ImageBootLogo2, 0);
    }
    if(event_code == LV_EVENT_SCREEN_LOADED) {
        _ui_screen_change(&ui_ScreenMain, LV_SCR_LOAD_ANIM_FADE_ON, 200, 4500, &ui_ScreenMain_screen_init); 
    }
}
