static void dropdown_symbol_adjust(lv_obj_t * dropdown)
{
    if(lv_dropdown_is_open(dropdown) == true)
        lv_dropdown_set_symbol(dropdown, LV_SYMBOL_LEFT);
    else
        lv_dropdown_set_symbol(dropdown, LV_SYMBOL_DOWN);
}
